const _audioCtx={c:null};
function playBeep(type){try{if(!_audioCtx.c)_audioCtx.c=new(window.AudioContext||window.webkitAudioContext)();const c=_audioCtx.c;if(c.state==="suspended")c.resume();const o=c.createOscillator();const g=c.createGain();o.connect(g);g.connect(c.destination);
  if(type==="ok"){o.frequency.value=880;g.gain.value=0.3;o.start();o.stop(c.currentTime+0.12)}
  else if(type==="dup"){o.frequency.value=220;o.type="square";g.gain.value=0.2;o.start();o.stop(c.currentTime+0.3)}
  else if(type==="error"){o.frequency.value=200;o.type="square";g.gain.value=0.4;o.start();o.stop(c.currentTime+0.5)}
  else{o.frequency.value=1200;g.gain.value=0.2;o.start();setTimeout(()=>{const o2=c.createOscillator();const g2=c.createGain();o2.connect(g2);g2.connect(c.destination);o2.frequency.value=1500;g2.gain.value=0.2;o2.start();o2.stop(c.currentTime+0.1)},150);o.stop(c.currentTime+0.1)}
}catch(e){}}
function fmt(n){return Number(n||0).toLocaleString("en-US")}
/* Format as integer with thousands separator — always rounds to whole number. Use for money. */
function fmt0(n){return Math.round(Number(n||0)).toLocaleString("en-US")}
function r2(n){return Math.round((n||0)*100)/100}
/* Format ISO date (YYYY-MM-DD) as Arabic-friendly (D-M-YYYY) for RTL display */
function fmtDate(iso){if(!iso)return"";const parts=String(iso).split("-");if(parts.length!==3)return iso;return parseInt(parts[2])+"-"+parseInt(parts[1])+"-"+parts[0]}
/* Convert decimal hours (e.g., 13.95) to display format "HH:MM" (e.g., "13:57").
   - 13.95 → "13:57"  (0.95 * 60 = 57 minutes)
   - 8.5   → "8:30"
   - 7.75  → "7:45" */
function hrsToHM(h){if(!h||h<=0)return"";const n=Number(h);if(isNaN(n))return"";const hh=Math.floor(n);const mm=Math.round((n-hh)*60);if(mm===60)return(hh+1)+":00";return hh+":"+String(mm).padStart(2,"0")}
/* Parse user input as either decimal (8.5) or HH:MM (8:30) → decimal hours.
   Accepts: "8", "8.5", "8:30", "8:5" (= 8:05), "8:", empty.
   Returns a number; 0 for empty/invalid. */
function parseHrs(s){if(s===""||s===null||s===undefined)return 0;const str=String(s).trim();if(!str)return 0;if(str.includes(":")){const[h,m]=str.split(":");const hh=parseInt(h)||0;const mm=parseInt(m)||0;return r2(hh+mm/60)}return parseFloat(str)||0}
function sqty(a){return(a||[]).reduce((s,c)=>s+(Number(c.qty)||0),0)}
function slay(a){return(a||[]).reduce((s,c)=>s+(Number(c.layers)||0),0)}
function setF(o,k,v){const c=JSON.parse(JSON.stringify(o));c[k]=v;return c}
