            /* Check which pieces are linked to fabrics */
            const linkedPieces=new Set();if(ord)FKEYS.forEach(k=>{if(gf(ord,k))(ord["fabricPieces"+k]||[]).forEach(p=>linkedPieces.add(p))});
            const hasFabric=ord?FKEYS.some(k=>gf(ord,k)):false;
