            <div style={{padding:8,borderRadius:10,background:"#8B5CF608",textAlign:"center"}}><div style={{fontSize:FS-3,color:T.textSec}}>الجرد</div><div style={{fontSize:FS+2,fontWeight:800,color:"#8B5CF6"}}>{totalCounted}</div></div>
